const crypto = require('crypto');

const authToken = $env.TWILIO_AUTH_TOKEN;
if (!authToken) throw new Error('TWILIO_AUTH_TOKEN env var not set');

const headers = $input.first().json.headers;
const body = $input.first().json.body;
const webhookUrl = $input.first().json.webhookUrl;

const twilioSignature = headers['x-twilio-signature'];

if (!twilioSignature) {
  return [{ json: { valid: false, reason: 'No X-Twilio-Signature header' } }];
}

const sortedKeys = Object.keys(body).sort();
let validationString = webhookUrl;
for (const key of sortedKeys) {
  validationString += key + (body[key] ?? '');
}

const expectedSignature = crypto
  .createHmac('sha1', authToken)
  .update(validationString, 'utf8')
  .digest('base64');

if (expectedSignature !== twilioSignature) {
  return [{ json: { valid: false, reason: 'Signature mismatch' } }];
}

return [{ json: { valid: true, ...body } }];
